// HCPA - Residência Médica 2024 (Acesso Direto)
export const HCPA_2024_QUESTIONS: any[] = [
  { id: "hcpa_2024_001", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Após falha na indução do parto vaginal e em razão de sofrimento fetal agudo, foi realizada cesariana em uma paciente com 39 semanas de gestação. Não havia registro de comorbidades no pré-natal. O recém-nascido apresentou cianose e não chorou. Após o clampeamento imediato do cordão umbilical, foi levado ao berço de reanimação, secado, estimulado e avaliado. A frequência cardíaca era de 30 bpm e observou-se apneia. Diante do quadro, qual a conduta imediata mais adequada?", options: ["Iniciar massagem cardíaca externa e realizar cateterismo venoso umbilical.", "Iniciar ventilação com pressão positiva com balão autoinflável e máscara.", "Realizar intubação traqueal e ventilação com pressão positiva com balão autoinflável.", "Oferecer oxigênio a 100% por funil."], correctIndex: 1 },
  { id: "hcpa_2024_002", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "O nascimento de um recém-nascido (RN) com 37 semanas de idade gestacional ocorreu por via vaginal, sem necessidade de fórceps. A mãe tinha sorologia positiva para HIV, com carga viral indetectável coletada recentemente. O RN foi posicionado sobre o ventre materno e apresentou choro forte e tônus adequado. Segundo o Ministério da Saúde, a conduta mais adequada é solicitar o clampeamento do cordão umbilical", options: ["imediatamente e levar o RN para banho em água corrente assim que possível.", "imediatamente e levar o RN para o berço aquecido para monitorização e manobras iniciais de reanimação.", "após 60 segundos de vida, manter o contato pele a pele e estimular a amamentação.", "após 60 segundos de vida, manter o contato pele a pele e contraindicar a amamentação."], correctIndex: 0 },
  { id: "hcpa_2024_003", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Gestante deu à luz um recém-nascido masculino, a termo, por parto vaginal. Na Caderneta da Gestante, constavam registros de 8 consultas pré-natais, teste rápido para sífilis positivo e VDRL de 1:2, amostras coletadas no primeiro trimestre de gestação. A gestante comprovou ter recebido 7.200.000 unidades de penicilina benzatina por 3 semanas, com intervalo nas doses de 1 semana cada, ainda no primeiro trimestre. Titulações de VDRL realizadas no segundo e no terceiro trimestres indicaram resultado de 1:2 e, por ocasião da admissão no Centro Obstétrico, de 1:1. O parceiro recebeu e realizou tratamento concomitantemente. A paciente referiu diagnóstico de sífilis em gestação anterior há 2 anos e apresentou comprovante de tratamento adequado e redução do VDRL de 1:16 para 1:2. Com base nessas informações e segundo o Protocolo Clínico e Diretrizes Terapêuticas para Prevenção da Transmissão Vertical de HIV, Sífilis e Hepatites Virais, publicado pelo Ministério da Saúde em 2022, qual a interpretação mais adequada e qual a conduta inicial?", options: ["Cicatriz sorológica – Não há necessidade de indicação de exames para o neonato ao nascimento.", "Cicatriz sorológica – Solicitar titulação de VDRL para o neonato ao nascimento.", "Sífilis adequadamente tratada nesta gestação – Solicitar titulação de VDRL para o neonato.", "Sífilis inadequadamente tratada nesta gestação – Solicitar titulação de VDRL, raio X de ossos longos e punção lombar com titulação de VDRL no líquor para o neonato."], correctIndex: 1 },
  { id: "hcpa_2024_004", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança nascida com 40 semanas de idade gestacional (parto vaginal, sem intercorrências no pré-natal ou no momento do parto), com peso ao nascimento de 3.500 g, encontrava-se sob cuidados no alojamento conjunto desde o nascimento. No primeiro dia de vida, apresentou dificuldade no posicionamento para mamar e na pega ao seio materno, tendo a mãe recebido orientações da equipe médica e da enfermagem em relação à amamentação, com sucesso imediato. No momento da alta, com 48 horas de vida, a criança estava mamando bem, em aleitamento materno exclusivo, com diurese e evacuações presentes. Não havia registro de queixas maternas de dor ou trauma mamilar. O peso no momento da alta era de 3.300 g. A mãe questionou sobre o freio língual. Com base na avaliação, pode-se afirmar que se trata de ..........; a conduta indicada é ..........", options: ["freio lingual com inserção normal – tranquilizar a mãe sobre a normalidade da situação", "anquiloglossia anterior – manter acompanhamento ambulatorial, pois a amamentação está adequada", "anquiloglossia anterior – indicar frenotomia pelo potencial prejuízo no aleitamento materno, na deglutição e na fala, a ser realizada em breve por odontologista ou médico cirurgião", "anquiloglossia submucosa – indicar frenotomia pelo potencial prejuízo no aleitamento materno, na deglutição e na fala, a ser realizada em breve por odontologista ou médico cirurgião"], correctIndex: 1 },
  { id: "hcpa_2024_005", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Durante consulta de puericultura em uma UBS em Porto Alegre, a mãe de uma criança de 2 anos solicitou informações gerais sobre a vacina contra febre amarela, especialmente porque a família viajava com frequência para o interior do Rio Grande do Sul. Assinale a assertiva correta sobre a vacina contra febre amarela, segundo as recomendações do Ministério da Saúde e do Programa Nacional de Imunizações.", options: ["Por ser uma vacina de vírus inativado, não há necessidade de avaliar se existe alguma contraindicação.", "Deve-se orientar a mãe sobre o fato de que a dose por via oral deverá ser repetida se a criança regurgitar, cuspir ou vomitar a vacina.", "Deve-se informar a mãe de que o esquema de vacinação para crianças prevê a aplicação de 1 dose (única).", "Deve-se informar a mãe de que a vacina está indicada, independentemente das viagens realizadas ou das que vierem a ser realizadas para o interior do estado ou para outros estados do Brasil."], correctIndex: 3 },
  { id: "hcpa_2024_006", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 3 meses foi trazido à UBS para consulta de revisão. Nasceu de parto vaginal, com 40 semanas de idade gestacional, Apgar 9/10, peso de 3.000 g e comprimento de 50 cm. Encontrava-se em regime de aleitamento materno exclusivo, com eliminações normais. A cobertura vacinal estava atualizada. Não havia história de intercorrências nos períodos pré-natal, perinatal e neonatal. O exame físico não revelou alterações, e o desenvolvimento neuropsicomotor era adequado para a idade. Considerando o crescimento próximo ao escore Z da curva da OMS, quais seriam as prováveis medidas antropométricas de peso e comprimento nessa consulta?", options: ["4.500 g – 53 cm", "5.500 g − 55 cm", "6.000 g – 61 cm", "6.500 g – 70 cm"], correctIndex: 2 },
  { id: "hcpa_2024_007", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino de 9 meses, com 8 kg, esteve internado por 24 horas na UPA por vômitos, distensão abdominal e fezes sanguinolentas. Ultrassonografia e radiografia de abdômen confirmaram invaginação intestinal. Foi transferido para um hospital terciário para realização de laparotomia, encontrando-se, à chegada, pálido, prostrado, hipoativo, febril (38º C), com frequência cardíaca de 160 bpm, olhos encovados, pulsos finos e enchimento capilar > 3 segundos. O abdômen estava muito distendido, com a sonda nasogástrica drenando secreção borrácea. Além de coletar amostras para culturas e iniciar o uso de antibióticos de amplo espectro, qual a conduta mais adequada e recomendada pelo Consenso de Sepse 2020?", options: ["Evitar bolo de cristaloides e optar por instalar soro de manutenção (100 ml/kg) com NaCl a 0,9%.", "Evitar bolo de cristaloides e optar por instalar soro de manutenção acrescido de perdas (150 ml/kg) com NaCl a 0,9%.", "Fazer bolo de 20 ml/kg de NaCl a 0,9% ou de Ringer-lactato para correr em 20 minutos, podendo ser repetido para melhorar a perfusão.", "Em função do quadro arrastado e das perdas para o terceiro espaço, fazer bolo com albumina a 5% (20 ml/kg), instalando, a seguir, soro de manutenção (100 ml/kg) com NaCl a 0,9%."], correctIndex: 2 },
  { id: "hcpa_2024_008", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Na Enfermaria Pediátrica, estão sendo avaliados os exames de um lactente de 10 meses, com comunicação interventricular ampla aguardando cirurgia corretiva, internado por broncopneumonia. Vinha recebendo ampicilina intravenosa (terceiro dia), oxigênio por cateter nasal (2 l/min), furosemida (0,5 mg/kg a cada 6 horas) e espironolactona (2 mg/kg/dia). Encontrava-se corado, alerta, com frequência respiratória de 40 mpm, pulsos amplos e frequência cardíaca de 160 bpm. A gasometria arterial revelou pH de 7,48, pCO2 de 60 mmHg, HCO3 de 31 mEq/l, pO2 de 110 mmHg, Na de 131 mEq/l, Cl de 101 mEq/l e K de 2,9 mEq/l. Como os achados da gasometria arterial podem ser classificados?", options: ["Alcalose metabólica, parcialmente compensada", "Acidose respiratória, parcialmente compensada", "Acidose mista", "Alcalose mista"], correctIndex: 0 },
  { id: "hcpa_2024_009", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Considerando o caso do lactente de 10 meses com comunicação interventricular, em uso de furosemida e espironolactona, com gasometria mostrando pH 7,48, pCO2 60 mmHg, HCO3 31 mEq/l, K 2,9 mEq/l, que medida terapêutica seria recomendável para contornar ou compensar a alteração visualizada à gasometria arterial?", options: ["Associar hidroclorotiazida.", "Aumentar a oferta de oxigênio.", "Aumentar a oferta de potássio.", "Aumentar a oferta de sódio."], correctIndex: 2 },
  { id: "hcpa_2024_010", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina de 10 meses foi trazida à consulta por dor abdominal, diarreia e vômitos após ingestão de fórmula infantil com proteína do leite de vaca (PLV). Tinha história de dermatite atópica. Nascida de parto vaginal, apresentou Apgar 8 e 9. Durante os primeiros 6 meses de vida, esteve assintomática, em uso de leite materno exclusivo. Testes alérgicos para o leite de vaca (dosagem de IgE específica) foram negativos. Há 1 mês vinha em uso de fórmula infantil polimérica com PLV sem lactose, sem melhora. No momento, a conduta mais adequada é iniciar", options: ["fórmula extensamente hidrolisada e suspender derivados de PLV.", "anti-histamínico e prednisolona.", "inibidor da bomba de prótons e procinéticos", "leite de cabra."], correctIndex: 0 },
  { id: "hcpa_2024_011", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente masculino, de 1 ano, iniciou, há 3 dias, com tosse, coriza hialina e temperatura axilar de até 37o C. Por ter apresentado piora clínica com taquipneia, batimentos de asa nasal e retrações intercostais e subcostais, foi trazido à consulta. A ausculta pulmonar revelou estertores rudes e crepitantes difusamente distribuídos, sem sibilância. Que agente etiológico está mais provavelmente relacionado ao caso?", options: ["Streptococcus pneumoniae", "Mycoplasma pneumoniae", "Haemophilus influenzae", "Rhinovirus"], correctIndex: 3 },
  { id: "hcpa_2024_012", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente de 2 anos foi trazido à Emergência por febre, irritabilidade, má perfusão periférica e presença de petéquias no abdômen e nos membros inferiores. Considerando que será realizada punção lombar, que medicamento é o recomendado por seu melhor efeito sedativo e segurança de uso?", options: ["Cetamina", "Codeína", "Diazepam", "Dexmedetomidina"], correctIndex: 0 },
  { id: "hcpa_2024_013", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino de 3 anos foi trazido à Emergência por ter a mãe percebido massa abdominal palpável enquanto o vestia após o banho, sem outras queixas. Ao exame físico, a criança estava em bom estado geral, eupneica, ativa e hipocorada 2+/4+. As auscultas cardíaca e respiratória estavam normais, e o abdômen flácido e depressível, com massa palpável no flanco esquerdo. Apresentava hipertensão arterial sistêmica e hematúria microscópica (constatada ao EQU). Diante da apresentação clínica, do exame físico e do resultado do EQU, qual o diagnóstico mais provável?", options: ["Linfoma de Burkitt", "Fecaloma", "Tumor de Wilms", "Pielonefrite"], correctIndex: 2 },
  { id: "hcpa_2024_014", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Pré-escolar de 4 anos foi trazido à Emergência por ter apresentado crise convulsiva na vigência de febre, caracterizada pela família como tônico-clônica generalizada, com duração de cerca de 1 minuto. A criança foi diagnosticada com otite média aguda. O exame neurológico estava normal. Embora a pediatra de plantão tenha orientado os familiares sobre crises convulsivas febris, eles permaneciam preocupados, desejando saber sobre os riscos de novos eventos semelhantes. Assinale a alternativa que contempla um fator associado à recorrência de crise febril.", options: ["Primeira crise tardia (após 18 meses)", "Crise na vigência de febre acima de 39o C", "Histórico familiar de epilepsia", "Histórico familiar de crise convulsiva febril"], correctIndex: 3 },
  { id: "hcpa_2024_015", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Pré-escolar de 4 anos foi trazido à Emergência por pico febril isolado de 37,8o C e tosse produtiva, quadro com início há 2 dias. A mãe informou que o filho, nascido com 35 semanas de idade gestacional, vinha tendo problemas respiratórios recorrentes desde os 3 meses de vida. Referiu 4 internações prévias por sibilância com pneumonia associada, uso de oxigenoterapia por cânula nasal e antibioticoterapia. Segundo ela, o filho nunca ficava completamente assintomático após as altas, persistindo com tosse diária. À admissão, peso e estatura encontravam-se no escore Z -3. Constatou-se baqueteamento digital bilateralmente. O exame físico revelou leve tiragem subcostal, e a ausculta pulmonar, estertores bolhosos difusos e sibilos telexpiratórios esparsos. Foi instituído o tratamento indicado para quadro agudo e recomendou-se que a criança fosse investigada pela possibilidade de", options: ["cardiopatia congênita com repercussão hemodinâmica.", "fibrose cística.", "displasia broncopulmonar.", "asma grave."], correctIndex: 1 },
  { id: "hcpa_2024_016", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança de 7 anos foi trazida à consulta por apresentar lesões maculopapulares avermelhadas. A mãe informou que o início do quadro fora precedido por febre baixa. Inicialmente surgiram lesões na face (bochechas e dorso do nariz) e, após 2 dias, espalharam-se nos membros superiores, inclusive nas palmas das mãos, com aspecto rendilhado. Elas acentuavam-se com o sol. Qual o diagnóstico mais provável?", options: ["Escarlatina", "Eritema infeccioso", "Exantema súbito", "Síndrome mão-pé-boca"], correctIndex: 1 },
  { id: "hcpa_2024_017", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança de 8 anos foi trazida à consulta pela terceira vez em menos de 2 meses por dificuldade respiratória, tosse e sibilância. O médico que costumeiramente atendia a criança propôs à mãe um tratamento com medicamento à base de componentes naturais ainda em fase experimental, veiculado em anúncio nas redes sociais. A mãe aceitou a proposta e levou o produto para casa com as recomendações médicas. Com base nesse quadro, assinale a assertiva correta.", options: ["Uma vez que a responsável pela criança aceitou a proposta terapêutica, não há impedimento para o uso desse medicamento.", "Para o uso desse medicamento, a criança deveria ter sido consultada e ter assinado termo de assentimento.", "Produtos farmacêuticos que ainda não foram liberados pela Anvisa podem ser prescritos e utilizados mediante autorização do paciente ou do responsável.", "Para produtos farmacêuticos ainda em fase de pesquisa, a participação de pacientes deve ser precedida da assinatura do termo de consentimento livre e esclarecido, onde conste a aprovação de protocolo para a realização da pesquisa em seres humanos."], correctIndex: 3 },
  { id: "hcpa_2024_018", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino de 9 anos foi trazido à Emergência por febre, dor no membro inferior esquerdo e dificuldade de mobilização do joelho há 24 horas. Não tinha história de traumatismos recentes. Ao exame físico, encontrava-se febril, prostrado, com dor constante na perna referida, mas com boa perfusão periférica. Nos membros inferiores, não se constatou perda de força; foram observadas diversas lesões ora pustulosas, ora crostosas e melicéricas, com halo hiperemiado. O joelho esquerdo estava quente e edemaciado. Com base na principal hipótese diagnóstica, o antibiótico recomendado para o paciente é", options: ["amoxicilina.", "ampicilina.", "oxacilina.", "cefepima."], correctIndex: 2 },
  { id: "hcpa_2024_019", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Qual dos antibióticos abaixo não é indicado para profilaxia primária da febre reumática?", options: ["Sulfametoxazol + trimetoprim", "Amoxicilina", "Penicilina V oral", "Clindamicina"], correctIndex: 0 },
  { id: "hcpa_2024_020", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Adolescente de 12 anos foi transferido da UPA para um hospital terciário por febre e volumoso derrame pleural à direita, apesar de estar fazendo uso de ceftriaxona há 3 dias. À chegada, o paciente encontrava-se ativo, em bom estado geral, com leve tiragem intercostal. Análise do líquido pleural: proteínas 3,7 g/dl, LDH 390 U/l, pH 7,45, glicose 65 mg/dl, citológico 4.000 células/mm3 (80% linfócitos, 20% neutrófilos), adenosina desaminase 80 U/l. Exame sérico: proteínas totais 6,5 g/dl, LDH 200 U/l. Com base nos dados, pode-se afirmar que se trata de um", options: ["transudato; deve-se suspender a ceftriaxona e investigar a possibilidade de insuficiência cardíaca secundária a miocardite viral.", "transudato; deve-se investigar a possibilidade de hidrotórax hepático.", "exsudato; deve-se adicionar vancomicina ao esquema antimicrobiano.", "exsudato; deve-se suspender a ceftriaxona e iniciar esquema com rifampicina, pirazinamida, isoniazida e etambutol."], correctIndex: 3 },
  { id: "hcpa_2024_021", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Menina de 12 anos foi trazida à consulta por queixar-se de cansaço e de falta de disposição para estudar ou fazer os esportes de que gostava e praticava regularmente. A menarca, que ocorrera há 6 meses, teve duração de 12 dias e houve perda de coágulos. Atualmente os ciclos menstruais tinham 24-35 dias, com fluxo intenso e duração de 8 dias ou mais. O hemograma realizado recentemente mostrou hemoglobina de 9,0 g/dl e ferritina de 5,0 ng/l. Ao exame físico, apresentava peso e altura adequados, M4 e P4 (estágios de Tanner). Qual a hipótese diagnóstica mais provável?", options: ["Imaturidade do eixo hipotálamo-hipófise-ovário", "Síndrome dos ovários policísticos", "Hipotireoidismo", "Coagulopatia"], correctIndex: 0 },
  { id: "hcpa_2024_022", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a alternativa que contempla as recomendações do Ministério da Saúde sobre a vacina contra o papilomavírus humano (HPV), disponível no Sistema Único de Saúde.", options: ["Bivalente: 2 doses para meninos e meninas dos 9 aos 14 anos e 2 doses para pessoas com imunossupressão dos 9 aos 45 anos", "Quadrivalente: 2 doses para meninos e meninas dos 9 aos 14 anos e 2 doses para pessoas com imunossupressão dos 9 aos 45 anos", "Quadrivalente: 2 doses para meninos e meninas dos 9 aos 14 anos e 3 doses para pessoas com imunossupressão dos 9 aos 45 anos", "Nonavalente: 2 doses para meninos e meninas dos 9 aos 14 anos e 3 doses para pessoas com imunossupressão dos 9 aos 45 anos"], correctIndex: 2 },
  { id: "hcpa_2024_023", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 34 anos engravidou há 2 anos. Na ocasião, a ultrassonografia realizada com 7 semanas revelou ovo cego. Após 2 semanas, apresentou sangramento intenso e iniciou o uso de anticoncepcional combinado oral (ACO). Há 5 meses, por desejar gestar, interrompeu o uso de ACO. À consulta, informou que seus ciclos menstruais eram regulares e que o esposo tinha 2 filhos de outro relacionamento. Trouxe ultrassonografia transvaginal que mostrou um mioma único, de 5,0 x 6,0 cm. Referiu ter medo de novo abortamento. Com base no quadro clínico e na imagem ultrassonográfica, que conduta é a mais adequada?", options: ["Realizar histeroscopia e retirar o mioma.", "Iniciar anticoncepção e retirar o mioma por laparoscopia.", "Tranquilizar a paciente e repetir a ultrassonografia transvaginal.", "Tranquilizar a paciente e orientar retorno se não engravidar em 7-8 meses."], correctIndex: 3 },
  { id: "hcpa_2024_024", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente com 17 semanas de gestação veio ao pré-natal queixando-se de corrimento vaginal com odor fétido. Ao exame, observou-se leucorreia acinzentada, com teste do odor positivo. Exame direto do conteúdo vaginal indicou redução acentuada de lactobacilos e presença de clue cells. Considerando o quadro clínico, assinale a assertiva incorreta.", options: ["Para o tratamento, metronidazol deve ser utilizado por via tópica (creme vaginal) visto que seu uso sistêmico é contraindicado pelo risco de teratogênese.", "Uma opção terapêutica eficaz e segura é a prescrição de metronidazol 500 mg, por via oral, de 12/12 horas, por 7 dias.", "O tratamento é necessário, pois a ocorrência desse quadro clínico durante a gestação está associada a vários desfechos obstétricos negativos.", "O quadro clínico apresenta associação com ruptura prematura de membranas e endometrite pós-parto."], correctIndex: 0 },
  { id: "hcpa_2024_025", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 29 anos, assintomática, veio à consulta para avaliação ginecológica. Trouxe laudos de exames citopatológicos (CP) de colo uterino negativos realizados aos 25 e aos 26 anos. Há 30 dias, coletou material para novo CP, cujo resultado indicou: Satisfatório para avaliação, células escamosas atípicas de significado indeterminado (ASC-US), flora sugestiva de vaginose. Diante desse resultado, qual a recomendação do Ministério da Saúde?", options: ["Tratar a vaginose e repetir o CP em 3 meses.", "Tratar a vaginose e repetir o CP em 12 meses.", "Solicitar colposcopia e, se sem alterações, repetir o CP em 3 meses, sem necessidade de tratar a vaginose por ser a paciente assintomática.", "Solicitar colposcopia e, se sem alterações, repetir o CP em 6 meses, sem necessidade de tratar a vaginose por ser a paciente assintomática."], correctIndex: 1 },
  { id: "hcpa_2024_026", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Casal em investigação de fertilidade trouxe à consulta resultados de espermograma e de exames hormonais normais. A paciente tinha história de internação por doença inflamatória pélvica. Que opção é o exame padrão ouro para avaliar a anatomia pélvica feminina?", options: ["Laparoscopia", "Histerossalpingografia", "Histeroscopia", "Ressonância magnética da pelve"], correctIndex: 0 },
  { id: "hcpa_2024_027", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 25 anos veio à consulta por não menstruar há 9 meses. Informou que seus ciclos menstruais variavam de 25-40 dias e que não estava grávida, embora não fizesse uso de métodos contraceptivos. Ao ser questionada sobre outros sintomas, referiu apenas perda de peso (3 kg). Relatou ter corrido uma maratona há 3 meses e estar se preparando para a próxima (em 2 semanas). O IMC era de 21 kg/m². Considerando as dosagens de referência das gonadotrofinas, assinale a alternativa que contempla os valores esperados para o caso.", options: ["FSH de 1,5 mUI/ml – LH de 1,0 mUI/ml", "FSH de 5,0 mUI/ml – LH de 15,0 mUI/ml", "FSH de 25,0 mUI/ml – LH de 10,0 mUI/ml", "FSH de 30,0 mUI/ml – LH de 2,0 mUI/ml"], correctIndex: 0 },
  { id: "hcpa_2024_028", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 39 anos, com IMC de 40 kg/m², consultou na UBS por sangramento uterino irregular e volumoso, quadro iniciado há 8 meses. Informou fazer uso de enalapril e manifestou desejo de gestar. Não foram constatadas alterações ao exame especular. Trouxe hemograma normal e dosagem de progesterona baixa. A ultrassonografia revelou endométrio de 20 mm de espessura e mioma subseroso de 3,0 cm e intramural de 2,0 cm. Qual a conduta mais adequada?", options: ["Indicar o uso de anticoncepcional combinado oral para regularizar o ciclo e, após, tentar induzir a ovulação.", "Indicar histeroscopia diagnóstica.", "Realizar biópsia de endométrio.", "Encaminhar a paciente para avaliação de cirurgia bariátrica."], correctIndex: 2 },
  { id: "hcpa_2024_029", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 55 anos, G2P2, consultou por vir apresentando, nos últimos 2 anos, vários episódios de calorões intensos, piora da qualidade do sono e maior irritabilidade. Referiu que, há 6 meses, iniciara com ressecamento vaginal e dispareunia. Submetera-se a histerectomia com salpingooforectomia bilateral há 2 anos, por miomatose. Em seu histórico, constavam diabetes melito e hipertensão arterial. Negou neoplasia, tabagismo ou ingestão de álcool. PA 120/84 mmHg, IMC 28 kg/m², mamas normais; atrofia vaginal ao exame. Mamografia e citologia normais há 8 meses. TSH normal, glicemia 88 mg/dl, colesterol 198 mg/dl, HDL 40 mg/dl, triglicerídios 190 mg/dl. Com base no quadro, deve-se prescrever", options: ["progesterona por via vaginal e fluoxetina.", "associação de estradiol e noretisterona por via oral.", "estriol por via vaginal e acetato de medroxiprogesterona oral.", "estradiol por via transdérmica (por gel ou adesivo)."], correctIndex: 3 },
  { id: "hcpa_2024_030", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 62 anos veio à consulta por apresentar episódios intermitentes de sangramento vaginal após a menopausa. A investigação diagnóstica identificou adenocarcinoma não endometrioide do endométrio. Com base na patogênese da neoplasia e no grupo histológico específico, é possível afirmar que", options: ["há associação entre esse tipo de adenocarcinoma e obesidade e diabetes melito.", "o tumor apresenta como marcador biomolecular mutação em p53.", "a doença tem comportamento biológico indolente e pouco agressivo.", "o tratamento cirúrgico indicado é histerectomia com salpingooforectomia bilateral sem estadiamento cirúrgico."], correctIndex: 1 },
  { id: "hcpa_2024_031", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Segundo orientações do Ministério da Saúde, para casos de pré-natal de risco habitual deve-se", options: ["solicitar sorologias para rubéola e citomegalovírus no primeiro trimestre, dada a alta prevalência dessas infecções no país.", "iniciar suplementação polivitamínica no primeiro trimestre.", "realizar exame especular e, se indicado, coletar material para exame citopatológico de colo uterino.", "realizar exame cultural de material vaginal e perianal para pesquisa de Streptococcus do grupo B no segundo trimestre."], correctIndex: 2 },
  { id: "hcpa_2024_032", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a assertiva correta sobre vacinação na gestação, conforme orientações do Ministério da Saúde.", options: ["Grávidas não necessitam receber a vacina dTpa, caso já a tenham recebido em gestação anterior.", "O esquema vacinal de difteria e tétano completo é de 3 doses, devendo ser reforçada a cada 10 anos.", "A vacina contra Haemophilus influenzae é contraindicada na gestação.", "Na ausência da vacina Pfizer/BioNTech contra covid-19, a segunda opção é a CoronaVac/Sinovac/Butantan."], correctIndex: 1 },
  { id: "hcpa_2024_033", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 19 anos veio à Emergência por dor abdominal e sangramento. Relatou um abortamento espontâneo há 2 dias. À admissão, temperatura 38,2o C, PA 90/60 mmHg, FC 110 bpm; sangramento vaginal em pequena quantidade e odor fétido; colo uterino aberto, abdômen doloroso, útero de aproximadamente 12 semanas. Hemograma: 15.000 leucócitos/mm³ e 10% de bastões. USG: útero antevertido, restos ovulares de aproximadamente 30 mm, ausência de feto ou partes ósseas. Assinale a assertiva correta.", options: ["O diagnóstico e a conduta dependem do resultado de uma ultrassonografia transvaginal.", "A conduta deve incluir internação hospitalar, exames laboratoriais, reposição volêmica e esvaziamento uterino após 12-24 horas de antibioticoterapia intravenosa de amplo espectro.", "Coagulação intravascular disseminada, insuficiência renal aguda, formação de abscesso tubo-ovariano e histerectomia são complicações possíveis.", "DIUs hormonal e de cobre são considerados categoria 2 nos critérios de elegibilidade, constituindo opções contraceptivas adequadas neste momento."], correctIndex: 2 },
  { id: "hcpa_2024_034", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a assertiva correta sobre os principais métodos de avaliação da saúde fetal.", options: ["Um traçado de cardiotocografia intraparto indicando ausência de variabilidade e presença de desacelerações variáveis recorrentes configura a categoria III, condição que requer intervenção imediata pelo risco de acidemia fetal.", "A avaliação com perfil biofísico fetal deve ser realizada após 30 semanas de gestação; se realizada antes, a prematuridade pode influenciar os movimentos respiratórios e corporais do feto.", "A avaliação do líquido amniótico com a utilização do índice de líquido amniótico (ILA), em lugar do lago vertical > 2,0 cm, diminui o número de cesarianas e melhora o desfecho perinatal.", "Ao estudo Doppler, quanto maior a resistência periférica do território vascular avaliado, maior será a velocidade do fluxo na diástole e menor será o índice de pulsatilidade (IP)."], correctIndex: 0 },
  { id: "hcpa_2024_035", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 40 anos, com 32 semanas de gestação (história de 3 partos vaginais), chegou à Emergência Obstétrica com sangramento súbito. BCF 160 bpm, dinâmica uterina ausente. Sangue escuro em pequena quantidade, colo sem dilatação. USG: placenta no segmento uterino inferior, borda a 1,8 cm do OCI, cordão de inserção central. Durante cardiotocografia (padrão não reativo), a paciente iniciou dor abdominal, hipertonia uterina e sangramento vaginal intenso, taquicardia, taquipneia e sudorese. Toque: 2,0 cm de dilatação. Quais os diagnósticos mais prováveis e a conduta mais adequada?", options: ["Placenta prévia e descolamento prematuro de placenta – Transfundir 2 unidades de hemoderivados e observar a evolução para o parto vaginal.", "Placenta com implantação baixa e descolamento prematuro de placenta – Realizar teste do coágulo e cesariana de emergência.", "Placenta prévia e trabalho de parto pré-termo – Realizar tocólise com nifedipina e administrar corticosteroide para amadurecimento pulmonar fetal.", "Vasa prévia e acretismo placentário – Realizar cesariana com cateterização ureteral e interrupção temporária de fluxo em artérias hipogástricas por técnica endovascular."], correctIndex: 1 },
  { id: "hcpa_2024_036", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primigesta de 24 anos, com 23 semanas de gestação, procurou a Emergência Obstétrica queixando-se de dor abdominal difusa e inapetência há 36 horas e de um episódio de vômito. IMC 23 kg/m², FC 122 bpm, FR 20 mpm, temperatura axilar 37,8o C, PA 90/50 mmHg. Altura uterina 23 cm, dor à palpação profunda do flanco direito. Sinal de Murphy negativo. BCF 160 bpm sem desacelerações, sem dinâmica uterina. Exame especular sem perda líquida ou sangramento. Colo fechado. Qual a hipótese diagnóstica mais provável e o exame complementar indicado?", options: ["Apendicite aguda – ultrassonografia abdominal", "Pielonefrite aguda – ultrassonografia do aparelho urinário", "Infecção ovular – ultrassonografia obstétrica", "Colecistite aguda – ultrassonografia de vias biliares"], correctIndex: 0 },
  { id: "hcpa_2024_037", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Tercigesta de 39 anos, com 16 semanas de gestação, apresentou, na consulta pré-natal, glicemia em jejum de 133 mg/dl e HbA1c de 6,3%. Referiu que, nas gestações anteriores há mais de 10 anos, não houve qualquer intercorrência. Qual o diagnóstico mais provável?", options: ["Diabetes gestacional", "Diabetes diagnosticado na gestação", "Diabetes pré-gestacional", "Pré-diabetes"], correctIndex: 1 },
  { id: "hcpa_2024_038", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primigesta com gestação a termo foi submetida a cesariana devido à apresentação pélvica e a trabalho de parto inicial. Durante o procedimento, ocorreu retenção inadvertida de uma compressa na cavidade abdominal, que passou despercebida pela equipe assistencial. No vigésimo dia pós-operatório, a paciente foi trazida à Emergência por obstrução intestinal, com necrose de alça intestinal e necessidade de colostomia. Com base no caso, assinale a assertiva correta em relação às definições de qualidade assistencial.", options: ["Retenção de compressa e obstrução intestinal são eventos adversos.", "Retenção de compressa e obstrução intestinal são eventos sentinelas.", "Retenção de compressa é um evento adverso, e obstrução intestinal, um evento sentinela.", "Retenção de compressa é um evento sentinela, e obstrução intestinal, um evento adverso."], correctIndex: 2 },
  { id: "hcpa_2024_039", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente com 27 semanas de gestação foi trazida à Emergência por dor retroesternal de início agudo, com histórico de cardiopatia isquêmica. ECG mostrou elevação do segmento ST e aumento de troponina e CK, compatíveis com síndrome coronariana aguda. Evoluiu para parada cardiorrespiratória. O médico plantonista da Obstetrícia chegou cerca de 5 minutos após o início das manobras de reanimação, sem resposta. Com base no quadro, deve-se", options: ["realizar imediatamente ultrassonografia materno-fetal com Doppler e encaminhar a paciente para a Unidade Coronariana se não houver onda A patológica.", "encaminhar a paciente imediatamente para a Unidade Coronariana.", "instalar cardiotocografia e contraindicar o uso de desfibrilador; se a cardiotocografia indicar categoria 2 ou 3, realizar cesariana.", "iniciar imediatamente cesariana com laparotomia mediana longitudinal infraumbilical."], correctIndex: 3 },
  { id: "hcpa_2024_040", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Puérpera relatou, na consulta de revisão, vir ocorrendo labilidade emocional, irritabilidade, insônia, tristeza e problemas com a amamentação, que comprometiam o cuidado do filho, quadro com início há 7 dias. Qual a conduta mais adequada no momento?", options: ["Tranquilizar a paciente e informar que esse é um período de adaptação à maternidade, mas a tendência é de melhora da situação.", "Prescrever um inibidor seletivo da recaptação da serotonina (sertralina, paroxetina, por exemplo) e indicar atendimento psicoterápico.", "Prescrever um antipsicótico atípico (clozapina, por exemplo) e encaminhar a paciente para Emergência Psiquiátrica.", "Indicar internação para a proteção do binômio mãe-bebê."], correctIndex: 0 },
  { id: "hcpa_2024_041", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente com episódio prévio de trombose venosa profunda de membro inferior evoluiu com síndrome pós-trombótica. Que sinal ou sintoma não é esperado?", options: ["Sinal de Homans", "Edema", "Varizes", "Úlcera venosa"], correctIndex: 0 },
  { id: "hcpa_2024_042", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Lactente de 8 meses será submetido a uma cirurgia eletiva de hérnia umbilical. A criança encontrava-se saudável, sem nenhum problema médico conhecido. À admissão hospitalar, os pais informaram que a última mamada ocorrera há aproximadamente 3 horas. Qual a recomendação mais apropriada para o jejum pré-operatório do paciente?", options: ["Jejum de 2 horas para líquidos claros e de 4 horas para alimentos sólidos", "Jejum de 4 horas para leite materno e de 6 horas para alimentos sólidos", "Jejum de 6 horas para líquidos claros e de 8 horas para alimentos sólidos", "Jejum de 8 horas para leite materno e para alimentos sólidos"], correctIndex: 1 },
  { id: "hcpa_2024_043", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 65 anos, portador de prótese mitral metálica, com fibrilação atrial crônica, em uso crônico de varfarina, foi admitido para artroplastia total do quadril devido a osteoartrose grave. O INR encontrava-se no alvo terapêutico. Que abordagem é a mais adequada em relação à anticoagulação no perioperatório desse paciente?", options: ["Suspender a varfarina 1 semana antes da cirurgia e iniciar enoxaparina 40 mg SC, 1vez/dia, até 24 horas antes do procedimento, independentemente do INR.", "Suspender a varfarina 5 dias antes da cirurgia e solicitar INR; se INR < 2,0, iniciar enoxaparina 80 mg SC, de 12/12 horas, até 24 horas antes da cirurgia.", "Suspender a varfarina 5 dias antes da cirurgia e solicitar INR; se INR < 2,0, iniciar heparina não fracionada 5.000 UI, de 12/12 horas, até 12 horas antes da cirurgia.", "Continuar o uso da varfarina e administrar uma dose única de vitamina K antes da cirurgia."], correctIndex: 1 },
  { id: "hcpa_2024_044", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Considerando o paciente com prótese mitral metálica submetido a artroplastia total do quadril e havendo baixo risco de sangramento, quando o uso da varfarina e da heparina deve ser reiniciado após a cirurgia?", options: ["A varfarina não deve ser reiniciada.", "Após 12 horas da cirurgia", "No segundo dia pós-operatório", "No terceiro dia pós-operatório"], correctIndex: 2 },
  { id: "hcpa_2024_045", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 18 anos, veio à consulta queixando-se de cefaleia eventual e fraqueza, com intolerância ao exercício físico. Apresentava quadro típico de claudicação intermitente de membros inferiores. Negou comorbidades prévias. PA de 150/90 mmHg em ambos os membros superiores, com pulsos palpáveis e simétricos, e ausência de pulsos periféricos nos membros inferiores. Qual a suspeita diagnóstica mais provável?", options: ["Coarctação de aorta", "Doença de Behçet", "Arterite de Takayasu", "Doença vascular periférica"], correctIndex: 0 },
  { id: "hcpa_2024_046", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 62 anos, tabagista, veio à Emergência por dor súbita no membro inferior direito, iniciada há 6 horas, agachado em sua lavoura. Cerca de 1 hora depois, referiu não sentir mais a perna do joelho para baixo. Apresentava todos os pulsos no membro inferior esquerdo e somente pulso femoral no direito, palidez e déficit de sensibilidade, sem déficit de motricidade. Eco-Doppler demonstrou oclusão da artéria femoral superficial estendendo-se para poplítea e artérias da perna, com dilatação de 2,0 cm da poplítea. Assinale a assertiva correta sobre o diagnóstico inicial do caso.", options: ["Eco-Doppler é o exame diagnóstico suficiente para indicar o melhor método de revascularização.", "Ressonância magnética tem papel fundamental para detectar os vasos com baixo fluxo.", "Angiotomografia é o exame de escolha complementar para avaliar a anatomia do aneurisma e indicar o melhor método de revascularização.", "Arteriografia é o exame de escolha complementar por possibilitar avaliação do leito distal e indicar o melhor método de revascularização."], correctIndex: 3 },
  { id: "hcpa_2024_047", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 60 anos, com tabagismo crônico e hipertensão, foi trazido à Emergência por dor abdominal intensa e febre há 2 dias, com sinais de irritação peritoneal mais evidente na fossa ilíaca direita. Leucocitose com desvio à esquerda. TC de abdômen evidenciou apendicite aguda com abscesso periapendicular. Neste momento, a abordagem terapêutica mais apropriada é realizar", options: ["apendicectomia aberta para adequada drenagem do abscesso.", "apendicectomia com drenagem do abscesso por via laparoscópica.", "drenagem percutânea do abscesso.", "tratamento clínico com antibióticos."], correctIndex: 2 },
  { id: "hcpa_2024_048", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Há 3 objetivos fundamentais no tratamento de pacientes com doença do refluxo gastroesofágico e esôfago de Barrett: alívio permanente dos sintomas, cicatrização duradoura da esofagite concomitante e regressão da metaplasia intestinal/displasia do epitélio cilíndrico. Qual dos tratamentos abaixo consegue obter os melhores resultados terapêuticos em relação aos 3 aspectos citados?", options: ["Tratamento medicamentoso com bloqueadores da bomba de prótons", "Tratamento medicamentoso com bloqueadores da bomba de prótons associado a procinéticos", "Tratamento endoscópico: mucosectomia ou terapia ablativa", "Fundoplicatura laparoscópica"], correctIndex: 3 },
  { id: "hcpa_2024_049", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente feminina, de 72 anos, procurou atendimento após colonoscopia para investigar hematoquezia + anemia (hemoglobina 6,2 g/dl). Lesão no cólon transverso com adenocarcinoma. TC de abdômen: 5 lesões hepáticas < 3,0 cm, hipovasculares. TC de tórax sem sinais de doença metastática. CEA de 2,0 ng/ml (normal). Qual a conduta mais adequada?", options: ["Iniciar quimioterapia em caráter paliativo, pois o sangramento costuma cessar por completo após o início do tratamento.", "Indicar biópsia percutânea das lesões hepáticas, uma vez que a característica hipovascular não é comum em metástases do câncer colorretal; além disso, o CEA está dentro de valores normais.", "Indicar colectomia parcial para controle do sangramento e da anemia, programar quimioterapia pós-operatória e, conforme a resposta ao tratamento, planejar ressecção das metástases hepáticas.", "Indicar colectomia parcial para tratar o sangramento relacionado ao tumor primário e, na mesma internação, quimioembolização de ramos da veia porta para promover o controle das lesões hepáticas."], correctIndex: 2 },
  { id: "hcpa_2024_050", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente feminina, de 60 anos, ECOG 0, com cirrose pelo vírus da hepatite C (Child-Pugh A), sem hipertensão portal, alfa-fetoproteína 2,0 ng/ml (normal), veio à consulta para definir a conduta após TC de abdômen com contraste evidenciando nódulo hepático, com TC de tórax sem alterações significativas. Qual a conduta mais adequada?", options: ["Repetir o exame de imagem em 3 meses; caso haja crescimento da lesão, realizar alcoolização do nódulo por via percutânea.", "Indicar biópsia da lesão; caso se confirme carcinoma hepatocelular, realizar embolização do ramo esquerdo da veia porta como opção de tratamento.", "Programar tratamento com quimioembolização arterial da lesão.", "Indicar cirurgia para ressecção do nódulo."], correctIndex: 3 },
  { id: "hcpa_2024_051", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 58 anos, com obesidade (IMC 32,4 kg/m2), procurou a Emergência por dor no hipocôndrio direito irradiada para o dorso (intensidade 8/10), associada a colúria e acolia, quadro iniciado há 6 horas. Negou febre, prurido ou emagrecimento. Temperatura axilar 36,8oC, PA 156/92 mmHg, SpO2 97%. Mucosas ictéricas e dor somente à palpação profunda do QSD, sem interrupção da inspiração durante essa manobra. O quadro clínico é sugestivo de .........., tendo sido solicitada avaliação com colangiorressonância, USG ou TC de abdômen e indicado tratamento inicial, ainda na Emergência, com ...........", options: ["cólica biliar – analgesia intravenosa", "coledocolitíase – analgesia intravenosa e antibioticoterapia empírica", "coledocolitíase – analgesia intravenosa e antibioticoterapia intravenosa somente se houver sinais de colangite", "colecistite aguda – analgesia e antibioticoterapia intravenosas"], correctIndex: 2 },
  { id: "hcpa_2024_052", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Menina de 7 anos, com síndrome de Ehlers-Danlos e portadora de aneurismas intracranianos, foi trazida à Emergência por febre e dificuldade ventilatória há 48 horas. Redução de murmúrio vesicular na região inferior do hemitórax direito, com estertores audíveis. Radiografia: grande consolidação no lobo inferior direito e derrame pleural ipsilateral. USG torácica revelou volumoso derrame pleural, líquido espesso, septações e loculações. Qual a conduta mais indicada para o derrame pleural?", options: ["Drenagem pleural tubular fechada", "Drenagem pleural tubular + instilação de fibrinolítico intrapleural", "Toracoscopia + drenagem pleural tubular", "Toracotomia + decorticação pulmonar + drenagem pleural tubular"], correctIndex: 2 },
  { id: "hcpa_2024_053", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 50 anos, sem comorbidades, foi internado por politrauma em decorrência de queda de motocicleta. Drenagem de pneumotórax à direita (dreno retirado após 7 dias). Intubação orotraqueal na cena do acidente; extubação após 12 dias, sem traqueostomia. Alta 20 dias após a internação. Após 1 mês, passou a apresentar dispneia progressiva, tosse seca. Veio à Emergência com estridor e esforço ventilatório. Diante da principal hipótese diagnóstica, que conduta é mais adequada no momento?", options: ["Uso de broncodilatadores inalatórios e glicocorticoide intravenoso", "Broncoscopia para dilatação traqueal", "Cricotireoidostomia sob anestesia local", "Cirurgia de traqueoplastia"], correctIndex: 1 },
  { id: "hcpa_2024_054", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Presença de uma grande hérnia discal central constitui uma das condições relacionadas à doença degenerativa discal que determina tratamento de urgência. Quando localizada na região lombar, essa condição pode causar a síndrome de cauda equina, a qual apresenta todas as características abaixo, exceto", options: ["hiperreflexia patelar bilateral.", "incontinência urinária e/ou fecal.", "dor e distúrbios sensitivos nas duas pernas, com anestesia perianal e perineal.", "disfunção sexual."], correctIndex: 0 },
  { id: "hcpa_2024_055", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Classifica-se clinicamente o traumatismo craniano conforme sua gravidade, utilizando-se a Escala de Coma de Glasgow (ECG). O traumatismo é considerado grave quando o escore for inferior ou igual a", options: ["3", "6", "8", "12"], correctIndex: 2 },
  { id: "hcpa_2024_056", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente feminina, de 67 anos, veio à Emergência queixando-se de dor ocular intensa à direita irradiada a todo hemicrânio direito, início súbito há 8 horas, com náuseas e vômitos. Negou trauma ocular. Histórico de hipertensão e diabetes tipo 2. Olho direito: acuidade visual 20/200, injeção conjuntival importante, córnea esbranquiçado-azulada, olho duro à palpação, pupila semidilatada não reativa à luz. Com base nos achados, qual a conduta inicial mais adequada?", options: ["Administrar manitol a 20% 1,5 g/kg intravenoso durante 1 hora e iniciar tratamento com acetazolamida 250 mg oral, colírio timolol a 0,5% seguido de colírio pilocarpina a 2%.", "Administrar metilprednisolona 1 g + soro fisiológico a 0,9% 250 ml intravenoso (repetir o esquema durante 3 dias).", "Iniciar tratamento com colírio tobramicina a 0,3% + dexametasona a 0,1% e reavaliar em 48 horas.", "Solicitar ressonância magnética de crânio."], correctIndex: 0 },
  { id: "hcpa_2024_057", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Assinale a alternativa que contempla a correta associação entre o teste específico para exame de joelhos e a estrutura avaliada.", options: ["Teste da gaveta – ligamentos colaterais", "Teste da gaveta – ligamentos cruzados", "Teste de McMurray – ligamentos colaterais", "Teste de McMurray – ligamentos cruzados"], correctIndex: 1 },
  { id: "hcpa_2024_058", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "A investigação complementar com imagem é prática frequente na avaliação dos quadros de dor abdominal em Serviços de Emergência não obstétricos. Para qual das situações clínicas abaixo a ultrassonografia é o exame inicial mais indicado?", options: ["Obstrução intestinal", "Cálculo urinário", "Ingestão de corpo estranho", "Trauma abdominal fechado"], correctIndex: 3 },
  { id: "hcpa_2024_059", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Assinale a assertiva correta sobre câncer de canal anal.", options: ["Está diretamente associado à infecção pelo herpes-vírus tipo 2.", "O tratamento de escolha consiste em radioterapia e quimioterapia neoadjuvantes.", "Retossigmoidectomia anterior pode ser empregada como tratamento de resgate efetivo em tumores refratários ao tratamento inicial.", "Receptores de transplantes (órgãos sólidos) apresentam risco aumentado de desenvolver a doença."], correctIndex: 3 },
  { id: "hcpa_2024_060", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Paciente de 72 anos, trazido à consulta, encontrava-se alerta, porém falava pouco e de forma incompreensível; obedecia a comandos, mas não nomeava objetos. Foi constatada, também, perda de força no lado direito do corpo, com sinal de Babinski à direita. Quais os prováveis diagnósticos sindrômicos e topográfico?", options: ["Disartria e síndrome piramidal – córtex frontal esquerdo", "Obnubilação e síndrome de segundo neurônio – lesões difusas bilaterais", "Afasia de expressão e síndrome piramidal – córtex frontal esquerdo", "Disartria/anartria e síndrome de segundo neurônio – córtex ou cápsula interna à esquerda"], correctIndex: 2 },
  { id: "hcpa_2024_061", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Para qual das situações abaixo há indicação de profilaxia para endocardite bacteriana segundo as recomendações atuais?", options: ["Paciente com prótese biológica valvar aórtica que será submetido a extração dentária sob anestesia local.", "Paciente com diagnóstico de prolapso valvar mitral com sopro cardíaco que será submetido a procedimento dentário invasivo.", "Paciente com história de endocardite infecciosa mitral que irá realizar colonoscopia com biópsia.", "Paciente com comunicação interatrial tipo ostium secundum corrigida percutaneamente há 3 meses que irá realizar implante de dispositivo intrauterino."], correctIndex: 0 },
  { id: "hcpa_2024_062", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Paciente de 65 anos foi trazida à Emergência por dor retroesternal em aperto, quadro iniciado há 4 horas. Histórico de hipertensão e diabetes tipo 2, em uso de AAS, atorvastatina e losartana. PA 176/90 mmHg, FC 92 bpm, Killip I. A Emergência não dispõe de cateterismo cardíaco, e o hospital com hemodinâmica pode ser acessado em, no mínimo, 2 horas. Que estratégia tem melhor expectativa de benefício para a paciente?", options: ["Administrar um trombolítico intravenoso, iniciar a anticoagulação com heparina e transferir a paciente para hospital com condições de realizar angioplastia adjuvante imediatamente.", "Iniciar a terapia farmacológica agressiva sem a terapia de reperfusão, com dupla antiagregação plaquetária e heparina não fracionada.", "Iniciar o protocolo de alteplase intravenosa imediatamente e, se a reperfusão farmacológica falhar, transferir a paciente para outro hospital.", "Iniciar a dupla antiagregação plaquetária e transferir a paciente para hospital terciário, mesmo com atraso, considerando seu alto risco clínico."], correctIndex: 0 },
  { id: "hcpa_2024_063", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Assinale a alternativa que completa, correta e respectivamente, o parágrafo abaixo. O quadro de hiperaldosteronismo primário pode cursar com .........., sendo caracterizado por nível de renina plasmática ...........", options: ["hipopotassemia e alcalose metabólica – elevado", "hipopotassemia e alcalose metabólica – diminuído", "hipopotassemia e acidose respiratória – normal", "hiperpotassemia e acidose metabólica – diminuído"], correctIndex: 1 },
  { id: "hcpa_2024_064", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Paciente feminina, de 29 anos, consultou por vir observando alterações ungueais há 6 meses. Onicólise, onicorrexe e coloração amarelada em todas as unhas dos pés, acometendo mais de 50% do diâmetro das lâminas ungueais. Exame micológico direto evidenciou hifas septadas; exame cultural detectou Trichophyton rubrum. Diante do diagnóstico nosológico, assinale a alternativa que contempla o tratamento mais adequado.", options: ["Fluconazol tópico, 2 vezes/semana, por 1 ano", "Fluconazol 150 mg, por via oral, em dose única mensal, por 1 ano", "Itraconazol 100 mg, por via oral, em dias alternados, por 2 meses", "Terbinafina 250 mg, por via oral, 1 vez/dia, por 3 meses"], correctIndex: 1 },
  { id: "hcpa_2024_065", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Paciente feminina, de 35 anos, consultou para tratamento de obesidade. Peso usual 63 kg até os 25 anos, aumentou 20 kg na gestação. Mede 1,62 m, pesa 98 kg (IMC 37,3 kg/m²). Sem comorbidades. Referiu ter parado com o consumo de leite e frutas por orientação de uma nutricionista do Instagram que afirmou ser o leite inflamatório e as frutas causadoras de esteatose hepática. Também substituiu azeite por gordura de coco e adicionava aveia para baixar o índice glicêmico. Assinale a assertiva que contempla a informação correta sobre nutrição divulgada pelo perfil do Instagram.", options: ["Leite é um alimento inflamatório.", "Frutas causam esteatose hepática.", "Gordura de coco é mais saudável para cozinhar do que azeite de oliva.", "Adição de aveia reduz o índice glicêmico da refeição."], correctIndex: 3 },
  { id: "hcpa_2024_066", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Associe os medicamentos anti-hiperglicemiantes (Metformina, Sulfonilureias, Inibidores da DPP-4, Inibidores da SGLT-2, Agonistas do GLP-1) a seus respectivos benefícios comprovados em ensaios clínicos randomizados e metanálises: redução de desfechos microvasculares; redução de morte cardiovascular e de internação por insuficiência cardíaca; redução de acidente vascular encefálico. A sequência numérica correta, de cima para baixo, é", options: ["1 – 3 – 5", "1 – 4 – 3", "2 – 3 – 1", "2 – 4 – 5"], correctIndex: 1 },
  { id: "hcpa_2024_067", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Paciente masculino, de 28 anos, procurou atendimento por pirose e regurgitação (2-3 vezes/semana), especialmente após ingestão de alimentos gordurosos. Referiu melhora temporária com antiácidos. Ganho de 7 kg nos últimos 2 anos, atingindo 89 kg (IMC 29,7 kg/m2). Negou disfagia, odinofagia, hematêmese e melena. Sem anemia. Com base no quadro, qual a conduta mais adequada?", options: ["Orientação de medidas não farmacológicas e teste terapêutico com dose usual de inibidores da bomba de prótons por 4-8 semanas", "Endoscopia digestiva alta com biópsias do esôfago", "Manometria esofágica e pHmetria de 24 horas na vigência de uso de inibidores da bomba de prótons", "Manometria esofágica e pHmetria de 24 horas sem uso concomitante de inibidores da bomba de prótons"], correctIndex: 0 },
  { id: "hcpa_2024_068", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Paciente de 62 anos, com cirrose por hepatite C e álcool, foi trazido à Emergência por confusão mental e aumento de volume abdominal. Ascite, flapping e desorientação. Hemoglobina 9,3 g/dl, leucócitos 2.430/mm3, plaquetas 56.000/mm3, creatinina 2,3 mg/dl, sódio 132 mEq/l, TP 18,1 s e atividade 52%, bilirrubina total 2,8 mg/dl e direta 1,9 mg/dl. Assinale a assertiva correta.", options: ["Está indicada paracentese diagnóstica para pesquisa de peritonite bacteriana espontânea, que constitui infecção do líquido de ascite devido à translocação bacteriana e pode ser um desencadeante de encefalopatia hepática.", "Deve ser iniciada administração de diuréticos, sendo espironolactona a primeira opção para o manejo da ascite na cirrose.", "Deve ser considerada encefalopatia hepática, porém, para confirmação do diagnóstico, é necessário realizar dosagem de amônia sérica que apresenta relação direta com os sintomas.", "Ocorre hiponatremia na maioria dos pacientes com cirrose e ascite e pode ser um desencadeante de encefalopatia hepática, sendo recomendada restrição hídrica < 1,5 litro/dia quando a concentração de sódio sérica estiver < 135 mEq/l."], correctIndex: 0 },
  { id: "hcpa_2024_069", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Paciente feminina, de 78 anos, foi trazida à Emergência por sonolência excessiva há 5 dias, com diminuição da ingestão de líquidos e alimentos. Urina concentrada e malcheirosa. Histórico de hipotireoidismo e dor crônica nos joelhos, acompanhamento por esquecimentos e diminuição de funcionalidade há 1 ano. Uso diário de levotiroxina e amitriptilina (50 mg, há 2 anos). Acordava ao ser chamada, mas adormecia em poucos segundos e respondia de forma confusa. Sem sinais neurológicos focais. Com base no quadro, assinale a assertiva correta.", options: ["Deve-se usar a ferramenta de rastreio Mini Exame do Estado Mental para identificação dos componentes diagnósticos de delirium.", "Trata-se de delirium hipoativo, tendo como provável causa infecção urinária.", "Trata-se de quadro demencial em evolução, com piora da cognição e sonolência excessiva devido ao uso de amitriptilina.", "Trata-se de demência rapidamente progressiva, devendo-se realizar punção lombar para análise do líquor."], correctIndex: 1 },
  { id: "hcpa_2024_070", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Paciente feminina, de 48 anos, procurou a Emergência com cansaço progressivo há 3 semanas, agravado há 7 dias. Não menstruação recente com alterações. Palidez, taquicardia e sopro sistólico 2+/6+. Hemoglobina 5,0 g/dl, leucócitos normais, plaquetas normais, VCM 90 fl, RDW 15,5%, reticulócitos 300.000/mm³. Hematoscopia: policromatofilia e anisocitose. Os achados do hemograma e a contagem dos reticulócitos sugerem", options: ["anemia microcítica provavelmente por ferropenia secundária à menstruação.", "anemia macrocítica por deficiência de vitamina B12.", "anemia hipoproliferativa por deficiência de ferro.", "anemia hiperproliferativa provavelmente relacionada a hemólise."], correctIndex: 3 },
  { id: "hcpa_2024_071", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Paciente masculino, de 59 anos, tabagista, com hipertensão e dislipidemia (risco cardiovascular 10 anos de 25% pelo escore de Framingham), apresentou resultado de exame anti-HIV reagente. Negou infecções oportunistas ou sintomas constitucionais. Qual a conduta mais adequada no momento?", options: ["Retardar o início da terapia antirretroviral até melhor controle do quadro metabólico, uma vez que o uso dos antirretrovirais pode influenciar negativamente no risco cardiovascular do paciente.", "Iniciar a terapia antirretroviral independentemente dos valores de CD4 e carga viral, devendo esses exames serem solicitados apenas para avaliação do status imunológico e monitoramento posterior.", "Iniciar a terapia antirretroviral apenas se a contagem de CD4 ≤ 350 células/mm3, situação na qual o paciente teria maior risco de complicações secundárias à infecção pelo HIV.", "Solicitar contagem de CD4 e carga viral; caso o paciente seja um controlador de elite, o adiamento do início do uso dos antirretrovirais está indicado."], correctIndex: 1 },
  { id: "hcpa_2024_072", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Urgência e Emergência", text: "A acompanhante de um homem que sofreu um colapso súbito no saguão do aeroporto fez contato com o Serviço de Emergência. Que orientações devem ser fornecidas nesse momento, considerando que ela não é profissional de saúde?", options: ["Confirmar a ausência de pulso e orientar o início das compressões torácicas e da ventilação boca a boca.", "Confirmar a irresponsividade e a ausência de movimento respiratório normal e orientar o início das compressões torácicas enquanto aguarda a chegada de uma pessoa treinada para uso do desfibrilador externo automático (DEA).", "Confirmar a irresponsividade e a ausência de pulso e de qualquer movimento respiratório e orientar o início das compressões torácicas e da ventilação boca a boca.", "Confirmar a irresponsividade e a ausência de movimento respiratório normal e orientar o início das compressões torácicas e o uso do DEA."], correctIndex: 3 },
  { id: "hcpa_2024_073", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Urgência e Emergência", text: "Paciente feminina, de 45 anos, foi trazida à Emergência por febre alta, calafrios, dor lombar e sintomas urinários. Piúria e bacteriúria. Diagnosticada com pielonefrite aguda, iniciada terapia antibiótica intravenosa. Após 24 horas, evoluiu com sonolência, hipotensão e oligúria. Lactato de 2 mmol/l (VR: 0,5-1,6 mmol/l). Com base no quadro, assinale a assertiva correta.", options: ["O nível de lactato é irrelevante para o caso.", "O nível de lactato não tem relação com o prognóstico.", "A paciente tem diagnóstico de choque e deve ser internada na UTI.", "A paciente tem sepse e deve ser intubada imediatamente."], correctIndex: 2 },
  { id: "hcpa_2024_074", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Paciente feminina, de 52 anos, ex-tabagista, com hipertensão, veio à consulta por hematúria em EQU solicitado em check-up. Sem outras alterações. Assintomática do ponto de vista urológico. Com base no quadro, assinale a assertiva correta.", options: ["Sangramento menstrual é a causa mais provável para a hematúria.", "Hemácias dismórficas indicam sangramento glomerular.", "Urocultura é a próxima etapa da investigação.", "Não é necessária investigação adicional."], correctIndex: 1 },
  { id: "hcpa_2024_075", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Paciente masculino, de 30 anos, apresentou dor lombar à direita, sugestiva de cólica renal. USG constatou hidronefrose à direita, sem definição do fator obstrutivo. Com base no resultado, qual o próximo exame a ser solicitado?", options: ["Tomografia computadorizada de abdômen sem contraste", "Ressonância magnética de abdômen", "Radiografia simples de abdômen", "Pielografia excretora"], correctIndex: 0 },
  { id: "hcpa_2024_076", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Assinale a assertiva correta sobre cefaleia.", options: ["A resposta a antagonistas do receptor da serotonina ou a cetorolaco pode ser considerada um fator tranquilizador em relação a causas graves de cefaleia.", "Cefaleia em trovoada e cefaleia desencadeada por exercício ou por manobra de Valsalva são sinais de alarme em cefaleia.", "O achado de hipertensão arterial em um paciente que vem à Emergência por cefaleia é fator que afasta causas graves de cefaleia.", "Pacientes vivendo com HIV, desde que sob tratamento regular, ao apresentarem cefaleia nova, não requerem investigação adicional."], correctIndex: 1 },
  { id: "hcpa_2024_077", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Oncologia", text: "Assinale a assertiva correta sobre intervenções preventivas em Oncologia.", options: ["Intervenções que diminuam a incidência de câncer são sempre custo-efetivas.", "Rastreamento de câncer deve ser sempre oferecido para todos os tipos de câncer que tenham métodos diagnósticos adequados.", "Diagnóstico precoce de câncer deve ser sempre promovido, independentemente da extensão da neoplasia.", "Polivitamínicos devem ser prescritos como intervenção preventiva efetiva para diminuir o risco de câncer."], correctIndex: 1 },
  { id: "hcpa_2024_078", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Um paciente buscou atendimento por dispneia progressiva (com início há 1 ano) e crepitantes nas bases pulmonares à ausculta. A TC mostrou padrão característico. Qual o diagnóstico mais provável?", options: ["Pneumonia intersticial fibrosante", "Adenocarcinoma multifocal", "Fibrose cística", "Sequela de tuberculose"], correctIndex: 0 },
  { id: "hcpa_2024_079", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Paciente masculino, de 39 anos, com lombalgia noturna de início insidioso há 4 meses que amenizava com exercício, mas não com repouso, com resposta significativa mas transitória a AINEs. Elevação de PCR. Radiografia de coluna lombar e sacroilíacas sem alterações. Com base no quadro, qual a conduta mais adequada?", options: ["Prescrever fisioterapia.", "Iniciar glicocorticoide sistêmico.", "Solicitar ressonância magnética.", "Realizar infiltração de articulações interfacetárias."], correctIndex: 2 },
  { id: "hcpa_2024_080", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Nível de evidência e grau de recomendação são ferramentas importantes da Epidemiologia Clínica. Levando-se em conta as opções propostas, consideram-se com o melhor nível de evidência, de acordo com o sistema GRADE, as diretrizes baseadas em", options: ["recomendações de especialistas.", "estudos observacionais com controles históricos.", "revisões sistemáticas de estudos de caso-controle.", "revisões sistemáticas de estudos de coorte."], correctIndex: 3 },
  { id: "hcpa_2024_081", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em uma população hipotética, o risco de câncer de bexiga entre tabagistas é 30/1.000 habitantes e entre pessoas que não fumam é 10/1.000 habitantes. Estima-se que 20% da população seja tabagista. Qual o risco de câncer de bexiga atribuível ao tabagismo nessa população?", options: ["16/1.000 habitantes", "20/1.000 habitantes", "66,66%", "33,33%"], correctIndex: 1 },
  { id: "hcpa_2024_082", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "O gráfico das Curvas ROC de 4 testes diagnósticos mostra pontos 1, 2, 3 e 4. Qual dos pontos apresenta a maior especificidade?", options: ["1", "2", "3", "4"], correctIndex: 0 },
  { id: "hcpa_2024_083", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "A pirâmide etária refere-se a uma população de uma unidade com ESF, com 3.000 usuários cadastrados. O gestor solicita o cálculo da necessidade de exames para cumprir a meta anual de 40% para o indicador Razão de Exames Citopatológicos do Colo do Útero. Mulheres de 25 a 64 anos: 1.000. Assinale a alternativa que melhor descreve a população da faixa etária priorizada, o denominador da fórmula e a meta de 40% dos exames anuais.", options: ["1.000 – 333 – 133", "1.000 – 400 – 160", "1.200 – 400 – 160", "1.300 – 433 – 173"], correctIndex: 0 },
  { id: "hcpa_2024_084", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Os atributos de Atenção Primária à Saúde são classificados em essenciais e derivados. Assinale a alternativa que contempla um atributo essencial e um derivado respectivamente.", options: ["Acesso de primeiro contato – longitudinalidade", "Longitudinalidade – integralidade", "Coordenação do cuidado – orientação comunitária", "Orientação comunitária – competência cultural"], correctIndex: 2 },
  { id: "hcpa_2024_085", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "O Previne Brasil encerrou os repasses per capita dos Pisos de Atenção Básica Fixo e Variável, sendo os recursos federais repassados por capitação ponderada e pagamento por desempenho para ações prioritárias. Assinale a alternativa que contém os indicadores assistenciais para o pagamento por desempenho previstos no Previne Brasil.", options: ["Cobertura vacinal para influenza – percentual de pessoas com diabetes com solicitação de hemoglobina glicada – proporção de gestantes com atendimento odontológico realizado", "Cobertura vacinal pentavalente – percentual de pessoas com diabetes com solicitação de hemoglobina glicada – proporção de gestantes com atendimento odontológico realizado", "Cobertura vacinal pentavalente – percentual de pessoas com diabetes com hemoglobina glicada no alvo terapêutico – proporção de gestantes com 6 ou mais consultas de pré-natal, sendo a primeira consulta até a vigésima semana de gestação", "Cobertura vacinal para poliomielite inativada – percentual de pessoas com diabetes com hemoglobina glicada no alvo terapêutico – proporção de gestantes com atendimento odontológico realizado"], correctIndex: 2 },
  { id: "hcpa_2024_086", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Muitos autores estudam as variações das taxas de Internações por Condições Sensíveis à Atenção Primária (ICSAP) relacionadas a gênero e etnia. Associe as características da população (Minorias étnicas, Homens, Mulheres idosas, Mulheres em idade fértil, Crianças em idade escolar) às condições agudas e crônicas de ICSAP (Insuficiência cardíaca congestiva; Desidratação e infecção do rim e trato urinário; DPOC e angina). A sequência numérica correta, de cima para baixo, é", options: ["3 – 5 – 2", "2 – 4 – 1", "1 – 5 – 3", "1 – 3 – 2"], correctIndex: 2 },
  { id: "hcpa_2024_087", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Imunoensaios rápidos, ou simplesmente testes rápidos, constituem uma estratégia para ampliação da testagem diagnóstica de condições infecciosas no SUS. Todas as alternativas abaixo contemplam características dos testes rápidos, exceto uma. Assinale-a.", options: ["Permitem resultados em 2 horas.", "Não exigem infraestrutura laboratorial.", "São realizados por profissionais de saúde após breve capacitação.", "A capacitação dos profissionais de saúde pode ser realizada de forma presencial ou à distância."], correctIndex: 0 },
  { id: "hcpa_2024_088", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Paciente feminina, de 76 anos, foi trazida à UBS por uma vizinha (embora more com 3 filhos adultos). Estágio avançado de demência, importante prejuízo do autocuidado e provável sarcopenia. Não havia registro de acompanhamento ou retirada de medicamentos para diabetes e hipertensão. Confirmada a suspeita de negligência. Assinale a assertiva correta sobre as medidas de vigilância em saúde em situações como essa.", options: ["O Ministério Público e o Serviço Social devem ser acionados para as devidas averiguações, não sendo necessária notificação, por não haver suspeita de violência física ou sexual.", "Poderão ser feitas uma notificação de violência, por meio da ficha de notificação interpessoal do SINAN, e uma comunicação ao Ministério Público; caberá à acompanhante buscar a autoridade policial se assim o entender.", "A suspeita de violência deve ser notificada compulsoriamente pelo serviço de saúde; da mesma forma, o caso notificado deve ser comunicado obrigatoriamente à autoridade policial, ao Ministério Público e ao Conselho Municipal do Idoso.", "A suspeita de violência deve ser notificada compulsoriamente pelo serviço de saúde; já a comunicação à autoridade policial deve partir da paciente visto que se trata de quebra do sigilo médico, sendo vedada a denúncia por parte deste sem sua expressa autorização."], correctIndex: 0 },
  { id: "hcpa_2024_089", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Paciente feminina, de 14 anos, indígena Kaingang, foi trazida pela mãe à UBS vinculada ao DSEI Interior Sul, com dor na fossa ilíaca direita, rigidez abdominal e sinal de Blumberg positivo, com hipótese de apendicite aguda. A paciente deverá ser encaminhada para avaliação cirúrgica, seguindo a organização da PNASPI. Com base nessa situação, assinale a assertiva correta.", options: ["O médico da UBS, contratado pela Secretaria da Saúde do Estado do Rio Grande do Sul, pode telefonar e encaminhar a paciente para a emergência cirúrgica mais próxima.", "O médico da UBS deve respeitar a rede e o fluxo assistencial acordado pela Secretaria, cabendo a ele encaminhar a paciente para a emergência cirúrgica de referência do Município.", "No âmbito do Subsistema de Atenção à Saúde Indígena, os atendimentos de alta complexidade devem ocorrer em um hospital geral do DSEI, preparado para receber e tratar pacientes indígenas.", "Cada DSEI organiza a atenção básica à saúde dentro de seus territórios, e a atenção especializada e de urgência são realizadas de forma integrada e hierarquizada com a rede assistencial do SUS de sua respectiva região."], correctIndex: 3 },
  { id: "hcpa_2024_090", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina do Trabalho", text: "As doenças infecciosas e parasitárias relacionadas ao trabalho apresentam características que as distinguem dos demais grupos. Assinale a alternativa que relaciona a doença infecciosa ou parasitária à exposição ocupacional.", options: ["Leptospirose – trabalhadores de manutenção da rede de esgoto", "Brucelose – profissionais de saúde", "Tuberculose – profissionais de creche", "Hepatite A – veterinários"], correctIndex: 0 },
  { id: "hcpa_2024_091", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina do Trabalho", text: "Paciente masculino, de 42 anos, veio à Emergência com dor abdominal em cólica, severa, constipação intestinal, sem alívio com analgésicos. Fadiga, irritabilidade, dores articulares. Trabalha de forma autônoma com reciclagem de baterias automotivas. Exames: anemia, ácido úrico e creatinina elevados. Qual a hipótese diagnóstica mais provável?", options: ["Intoxicação por cromo", "Intoxicação por chumbo", "Doença inflamatória intestinal", "Parasitose intestinal"], correctIndex: 1 },
  { id: "hcpa_2024_092", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina do Trabalho", text: "A síndrome do túnel do carpo é caracterizada pela compressão do nervo mediano em sua passagem pelo canal do carpo, usualmente associada a tarefas de alta força e/ou repetitividade, mas pode ocorrer em outras condições. Assinale a alternativa que contempla uma condição clínica em que essa síndrome também pode ocorrer.", options: ["Puerpério", "Hipertensão arterial", "Hipertireoidismo", "Hipotireoidismo"], correctIndex: 3 },
  { id: "hcpa_2024_093", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Desastres naturais, como o ocorrido no Vale do Taquari/RS em 2023, podem causar sofrimento agudo e crônico para os afetados. Assinale a assertiva incorreta sobre o impacto psiquiátrico relacionado a desastres naturais.", options: ["Frequentemente, constatam-se ideações suicidas, caso em que intervenções breves são eficazes para o manejo da crise suicida.", "Para melhor entendimento do trauma, devem ser considerados fatores prévios e posteriores ao trauma em si, sendo os transtornos de personalidade os mais importantes e os mais frequentemente relacionados ao suicídio.", "O transtorno de estresse agudo é distinto do TEPT, pois seu padrão sintomático é restrito à duração de 3 dias a 1 mês depois da exposição ao evento traumático.", "Duas possíveis abordagens para tratamento de TEPT são terapia de exposição e prescrição de inibidores da recaptação de serotonina."], correctIndex: 1 },
  { id: "hcpa_2024_094", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Paciente feminina, de 19 anos, veio à consulta para acompanhamento do tratamento da asma. Assintomática ao exame, mas nas últimas 4 semanas (pelo menos 3 vezes/semana) teve sintomas de tosse e aperto no peito, necessitando de salbutamol inalado em cada ocasião. Acordou várias vezes à noite com falta de ar. Com base no relato e de acordo com o GINA 2023, pode-se afirmar que", options: ["não há elementos suficientes para avaliar com precisão o controle da asma.", "a asma não está controlada.", "a asma está parcialmente controlada.", "a asma está bem controlada."], correctIndex: 1 },
  { id: "hcpa_2024_095", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Paciente de 35 anos, trabalha em usina de reciclagem, veio à consulta por prurido há 2 meses, principalmente nas mãos, tronco e inguinal, maior à noite após o banho; companheira com queixas parecidas. Lesões papulovesiculosas simétricas em punhos, espaços interdigitais, cintura, axilas, nádegas, coxas, pênis e escroto. Assinale a assertiva correta sobre o tratamento dessa afecção cutânea.", options: ["A recidiva é comum por autoinfestação e por eclosão de ovos, sendo, portanto, necessário repetir o tratamento tópico a cada 3 dias.", "A persistência do prurido por semanas é frequente mesmo com o tratamento adequado.", "Tanto o tratamento oral quanto o tratamento tópico devem ser repetidos em 2 semanas.", "Deve-se evitar o uso de queratolíticos e de corticosteroides para reduzir recidiva e infecção secundária."], correctIndex: 1 },
  { id: "hcpa_2024_096", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Paciente feminina, de 52 anos, procurou atendimento por grande edema na face, pouco doloroso, início súbito há 2 dias. Negou prurido, dispneia, calafrios ou febre. Uso de hidroclorotiazida, captopril, sinvastatina e AAS. Tratamento com loratadina sem melhora. Edema difuso, assimétrico na hemiface esquerda e lábio superior, mínimo eritema, sem bolhas ou úlceras. Assinale a assertiva correta sobre o caso.", options: ["Edema na face persistente e sinais inflamatórios leves podem estar relacionados a doenças sistêmicas, incluindo tireoidopatias e infecções por Helicobacter pylori.", "Edema unilateral e doloroso sugere celulite de face relacionada a processo infeccioso odontogênico.", "Tempo de evolução sugere uma farmacodermia com mecanismo imunológico do tipo II, relacionada a uso de AAS ou hidroclorotiazida.", "Falta de resposta a loratadina e ausência de sinais de urticária sugerem uma reação mediada por bradicinina."], correctIndex: 3 },
  { id: "hcpa_2024_097", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Assinale a alternativa que preenche, correta e respectivamente, as lacunas sobre investigação de pacientes sintomáticos respiratórios. Pacientes com tosse persistente por .......... ou mais devem realizar ...........", options: ["2 semanas – coleta de 1 amostra de escarro para realização de teste rápido molecular para tuberculose", "2 semanas – coleta de 2 amostras de escarro em dias diferentes para pesquisa de BAAR", "3 semanas – coleta de 2 amostras de escarro em dias diferentes para pesquisa de BAAR", "3 semanas – radiografia de tórax e coleta de 3 amostras de escarro em dias diferentes para pesquisa de BAAR"], correctIndex: 2 },
  { id: "hcpa_2024_098", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem transgênero com sorologia negativa para HIV, relacionamento estável com homem cisgênero em tratamento regular para HIV e carga viral negativa, veio à consulta para avaliação de anticoncepção. Tinham outras parcerias sexuais, penetração vaginal e anal, uso de preservativo na maioria das relações. Tratamento para sífilis há 5 meses. Teste rápido HIV negativo. Diante do quadro, qual a recomendação mais adequada para anticoncepção e prevenção de HIV?", options: ["Medroxiprogesterona (150 mg) intramuscular a cada 3 meses e uso diário de tenofovir (TDF) (300 mg) + entricitabina (FTC) (200 mg)", "Undecanoato de testosterona a cada 3 meses e uso diário de TDF (300 mg) e lamivudina (3TC) (300 mg) + dolutegravir (50 mg) por 28 dias", "Anticoncepcional oral combinado contínuo e uso diário de TDF (300 mg) e 3TC (300 mg) + dolutegravir (50 mg) por 28 dias", "Anticoncepcional oral combinado com pausa e uso diário de TDF (300 mg) + FTC (200 mg)"], correctIndex: 0 },
  { id: "hcpa_2024_099", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "A Resolução CFM no 2.333/2023 estabelece normas éticas sobre a prescrição de terapias hormonais com esteroides androgênicos e anabolizantes, contraindicando seu uso para fins estéticos, de ganho de massa muscular ou de performance. Em relação ao uso de testosterona, a Resolução", options: ["pode ser questionada visto que a terapia hormonal cruzada para homens trans utiliza doses desse esteroide semelhantes às empregadas para fins estéticos ou de performance.", "autoriza que o paciente faça uso do livre-arbítrio para decidir sobre seus tratamentos, podendo o médico prescrever esse ou qualquer outro medicamento que julgar adequado.", "reafirma recomendações anteriores de sociedades científicas e se baseia em aspectos fundamentais de bioética, como o da não maleficência.", "prevê a realização de acompanhamento com médico com experiência na prescrição desse esteroide para fins de performance somente para atletas profissionais."], correctIndex: 2 },
  { id: "hcpa_2024_100", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Considerando os achados clínicos de dor lombar bilateral em trabalhador de madeireira, sem alteração ao exame neurológico, e uma radiografia de coluna lombossacra solicitada, qual estratégia de cuidado em Atenção Primária é adequada, entre diagnóstico sindrômico, etiológico, espera permitida ou procedimento evitável?", options: ["Espera permitida", "Diagnóstico etiológico", "Procedimento evitável", "Diagnóstico sindrômico"], correctIndex: 2 },
];
